from flask import Flask, request, jsonify
from web3 import Web3
import hashlib
import time
import secrets
from functools import wraps

app = Flask(__name__)
w3 = Web3()

# In-memory storage for nonce tracking (use Redis in production)
nonce_storage = {}

# Rate limiting
rate_limit_window = 60  # seconds
rate_limit_max_requests = 10
request_counts = {}

def rate_limit(max_requests=10, window=60):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            client_ip = request.remote_addr
            current_time = time.time()
            
            if client_ip not in request_counts:
                request_counts[client_ip] = []
            
            # Remove old requests
            request_counts[client_ip] = [
                req_time for req_time in request_counts[client_ip]
                if current_time - req_time < window
            ]
            
            if len(request_counts[client_ip]) >= max_requests:
                return jsonify({"error": "Rate limit exceeded"}), 429
            
            request_counts[client_ip].append(current_time)
            return f(*args, **kwargs)
        return decorated_function
    return decorator

def validate_signature(message, signature, address):
    try:
        # Recover address from signature
        recovered_address = w3.eth.account.recover_message(message, signature=signature)
        
        # Compare with provided address
        if recovered_address.lower() == address.lower():
            return True
        return False
    except Exception:
        return False

def generate_nonce():
    return secrets.token_hex(16)

def verify_nonce(address, nonce):
    if address not in nonce_storage:
        return False
    return nonce_storage[address] == nonce

def store_nonce(address, nonce):
    nonce_storage[address] = nonce
    # Auto-expire nonce after 5 minutes
    time.sleep(300)

@app.route('/auth/nonce', methods=['POST'])
@rate_limit()
def get_nonce():
    try:
        data = request.get_json()
        address = data.get('address')
        
        if not address or not w3.isAddress(address):
            return jsonify({"error": "Invalid address"}), 400
        
        nonce = generate_nonce()
        store_nonce(address, nonce)
        
        return jsonify({"nonce": nonce}), 200
    except Exception:
        return jsonify({"error": "Internal server error"}), 500

@app.route('/auth/verify', methods=['POST'])
@rate_limit()
def verify_signature():
    try:
        data = request.get_json()
        address = data.get('address')
        message = data.get('message')
        signature = data.get('signature')
        nonce = data.get('nonce')
        
        if not all([address, message, signature, nonce]):
            return jsonify({"error": "Missing required fields"}), 400
        
        if not w3.isAddress(address):
            return jsonify({"error": "Invalid address"}), 400
        
        # Verify nonce
        if not verify_nonce(address, nonce):
            return jsonify({"error": "Invalid or expired nonce"}), 400
        
        # Verify signature
        if not validate_signature(message, signature, address):
            return jsonify({"error": "Invalid signature"}), 401
        
        # Remove used nonce
        if address in nonce_storage:
            del nonce_storage[address]
        
        return jsonify({
            "success": True,
            "address": address
        }), 200
        
    except Exception:
        return jsonify({"error": "Internal server error"}), 500

